import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import api from "../api/axios";

export default function CreateEvent() {
  const navigate = useNavigate();
  const [categories, setCategories] = useState([]);
  const [errors, setErrors] = useState({});
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState({
    title: "",
    description: "",
    date: "",
    end_date: "",
    location: "",
    city: "",
    category: "",
    organizer_name: "",
    organizer_email: "",
    organizer_phone: "",
    website: "",
  });
  const [image, setImage] = useState(null);

  useEffect(() => {
    api.get("/events/categories/").then(({ data }) => setCategories(data)).catch(() => {});
  }, []);

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    setErrors({});
    setLoading(true);

    const formData = new FormData();
    Object.entries(form).forEach(([k, v]) => { if (v) formData.append(k, v); });
    if (image) formData.append("image", image);

    try {
      const { data } = await api.post("/events/", formData, {
        headers: { "Content-Type": "multipart/form-data" },
      });
      navigate(`/events/${data.id}`);
    } catch (err) {
      setErrors(err.response?.data || {});
    } finally {
      setLoading(false);
    }
  };

  const fieldError = (field) =>
    errors[field] ? <p className="text-red-600 text-xs mt-1">{errors[field][0] || errors[field]}</p> : null;

  return (
    <div className="max-w-2xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
      <h1 className="text-2xl font-bold text-gray-900 mb-6">Post a New Event</h1>

      <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6 sm:p-8">
        <form onSubmit={handleSubmit} className="space-y-5">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Event Title *</label>
            <input type="text" name="title" value={form.title} onChange={handleChange} required className="input" placeholder="e.g. Summer Jazz Festival" />
            {fieldError("title")}
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Description *</label>
            <textarea name="description" value={form.description} onChange={handleChange} required rows={4} className="input resize-none" placeholder="Tell people what to expect..." />
            {fieldError("description")}
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Start Date & Time *</label>
              <input type="datetime-local" name="date" value={form.date} onChange={handleChange} required className="input" />
              {fieldError("date")}
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">End Date & Time</label>
              <input type="datetime-local" name="end_date" value={form.end_date} onChange={handleChange} className="input" />
            </div>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Location / Venue *</label>
              <input type="text" name="location" value={form.location} onChange={handleChange} required className="input" placeholder="e.g. Central Park" />
              {fieldError("location")}
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">City</label>
              <input type="text" name="city" value={form.city} onChange={handleChange} className="input" placeholder="e.g. New York" />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Category</label>
            <select name="category" value={form.category} onChange={handleChange} className="input">
              <option value="">Select a category</option>
              {categories.map((cat) => (
                <option key={cat.id} value={cat.id}>{cat.name}</option>
              ))}
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Event Image</label>
            <input type="file" accept="image/*" onChange={(e) => setImage(e.target.files[0])} className="block w-full text-sm text-gray-500 file:mr-3 file:py-2 file:px-3 file:rounded-lg file:border-0 file:text-sm file:font-medium file:bg-primary-50 file:text-primary-700 hover:file:bg-primary-100" />
          </div>

          <div className="border-t border-gray-100 pt-4">
            <h3 className="text-sm font-semibold text-gray-700 mb-3">Organizer Details</h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Organizer Name</label>
                <input type="text" name="organizer_name" value={form.organizer_name} onChange={handleChange} className="input" placeholder="Your name or org name" />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Contact Email</label>
                <input type="email" name="organizer_email" value={form.organizer_email} onChange={handleChange} className="input" placeholder="contact@example.com" />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Phone</label>
                <input type="tel" name="organizer_phone" value={form.organizer_phone} onChange={handleChange} className="input" placeholder="+1 555 0000" />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Website</label>
                <input type="url" name="website" value={form.website} onChange={handleChange} className="input" placeholder="https://..." />
              </div>
            </div>
          </div>

          <div className="flex gap-3 pt-2">
            <button type="submit" disabled={loading} className="btn-primary">
              {loading ? "Submitting..." : "Submit Event"}
            </button>
            <button type="button" onClick={() => navigate(-1)} className="btn-secondary">
              Cancel
            </button>
          </div>

          <p className="text-xs text-gray-400">Events are reviewed before being published publicly.</p>
        </form>
      </div>
    </div>
  );
}
